import type { ComponentProps, ComponentRef } from 'react';
import { ImageCropper as ImageCropperPrimitive } from '@ark-ui/react/image-cropper';
import { clsx } from 'clsx';
import { forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './ImageCropper.module.css';

const ImageCropperRoot = forwardRef<
  ComponentRef<typeof ImageCropperPrimitive.Root>,
  ComponentProps<typeof ImageCropperPrimitive.Root>
>(function ImageCropperRoot({ className, ...props }, ref) {
  return (
    <ImageCropperPrimitive.Root
      ref={ref}
      data-slot="image-cropper-root"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const ImageCropperRootProvider = forwardRef<
  ComponentRef<typeof ImageCropperPrimitive.RootProvider>,
  ComponentProps<typeof ImageCropperPrimitive.RootProvider>
>(function ImageCropperRootProvider({ className, ...props }, ref) {
  return (
    <ImageCropperPrimitive.RootProvider
      ref={ref}
      data-slot="image-cropper-root-provider"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const ImageCropperViewport = forwardRef<
  ComponentRef<typeof ImageCropperPrimitive.Viewport>,
  ComponentProps<typeof ImageCropperPrimitive.Viewport>
>(function ImageCropperViewport({ className, ...props }, ref) {
  return (
    <ImageCropperPrimitive.Viewport
      ref={ref}
      data-slot="image-cropper-viewport"
      className={clsx(styles.viewport, normalizeClassName(className))}
      {...props}
    />
  );
});

const ImageCropperImage = forwardRef<
  ComponentRef<typeof ImageCropperPrimitive.Image>,
  ComponentProps<typeof ImageCropperPrimitive.Image>
>(function ImageCropperImage({ className, ...props }, ref) {
  return (
    <ImageCropperPrimitive.Image
      ref={ref}
      data-slot="image-cropper-image"
      className={clsx(styles.image, normalizeClassName(className))}
      {...props}
    />
  );
});

const ImageCropperSelection = forwardRef<
  ComponentRef<typeof ImageCropperPrimitive.Selection>,
  ComponentProps<typeof ImageCropperPrimitive.Selection>
>(function ImageCropperSelection({ className, ...props }, ref) {
  return (
    <ImageCropperPrimitive.Selection
      ref={ref}
      data-slot="image-cropper-selection"
      className={clsx(styles.selection, normalizeClassName(className))}
      {...props}
    />
  );
});

const ImageCropperGrid = forwardRef<
  ComponentRef<typeof ImageCropperPrimitive.Grid>,
  ComponentProps<typeof ImageCropperPrimitive.Grid>
>(function ImageCropperGrid({ className, ...props }, ref) {
  return (
    <ImageCropperPrimitive.Grid
      ref={ref}
      data-slot="image-cropper-grid"
      className={clsx(styles.grid, normalizeClassName(className))}
      {...props}
    />
  );
});

const ImageCropperHandle = forwardRef<
  ComponentRef<typeof ImageCropperPrimitive.Handle>,
  ComponentProps<typeof ImageCropperPrimitive.Handle>
>(function ImageCropperHandle({ className, ...props }, ref) {
  return (
    <ImageCropperPrimitive.Handle
      ref={ref}
      data-slot="image-cropper-handle"
      className={clsx(styles.handle, normalizeClassName(className))}
      {...props}
    />
  );
});

const ImageCropper = Object.assign(ImageCropperRoot, {
  Root: ImageCropperRoot,
  RootProvider: ImageCropperRootProvider,
  Viewport: ImageCropperViewport,
  Image: ImageCropperImage,
  Selection: ImageCropperSelection,
  Grid: ImageCropperGrid,
  Handle: ImageCropperHandle,
  handles: ImageCropperPrimitive.handles,
});

export { ImageCropper };

@layer ui.components {
  .root {
    box-sizing: border-box;
    display: grid;
    width: var(--image-cropper-width, 32rem);
    max-width: var(--image-cropper-max-width, 100%);
    gap: var(--image-cropper-gap, var(--spacing-3));
    color: var(--image-cropper-color, var(--color-foreground));

    &[data-dragging],
    &[data-panning] {
      cursor: grabbing;
    }
  }

  .viewport {
    box-sizing: border-box;
    width: 100%;
    height: var(--image-cropper-viewport-height, var(--image-cropper-viewport-min-height, 20rem));
    overflow: hidden;
    border: var(--image-cropper-border-width, var(--border-width-sm)) solid
      var(--image-cropper-border-color, var(--color-border));
    border-radius: var(--image-cropper-radius, var(--radius-lg));
    background:
      linear-gradient(
          45deg,
          var(
              --image-cropper-checker-color,
              color-mix(in oklab, var(--color-muted) 72%, transparent)
            )
            25%,
          transparent 25%
        )
        0 0 / var(--image-cropper-checker-size, 1rem) var(--image-cropper-checker-size, 1rem),
      linear-gradient(
          45deg,
          transparent 75%,
          var(
              --image-cropper-checker-color,
              color-mix(in oklab, var(--color-muted) 72%, transparent)
            )
            75%
        )
        0 0 / var(--image-cropper-checker-size, 1rem) var(--image-cropper-checker-size, 1rem),
      linear-gradient(
          45deg,
          transparent 75%,
          var(
              --image-cropper-checker-color,
              color-mix(in oklab, var(--color-muted) 72%, transparent)
            )
            75%
        )
        calc(var(--image-cropper-checker-size, 1rem) / -2)
        calc(var(--image-cropper-checker-size, 1rem) / -2) / var(--image-cropper-checker-size, 1rem)
        var(--image-cropper-checker-size, 1rem),
      linear-gradient(
          45deg,
          var(
              --image-cropper-checker-color,
              color-mix(in oklab, var(--color-muted) 72%, transparent)
            )
            25%,
          var(--image-cropper-viewport-bg, var(--color-background)) 25%
        )
        calc(var(--image-cropper-checker-size, 1rem) / -2)
        calc(var(--image-cropper-checker-size, 1rem) / -2) / var(--image-cropper-checker-size, 1rem)
        var(--image-cropper-checker-size, 1rem);
    box-shadow: var(--image-cropper-shadow, none);

    &[data-disabled] {
      cursor: default;
    }
  }

  .image {
    position: absolute;
    inset: 0;
    display: block;
    width: 100%;
    height: 100%;
    object-fit: contain;
    transform-origin: center;
    backface-visibility: hidden;
  }

  .selection {
    box-sizing: content-box;
    border: var(--image-cropper-selection-border-width, var(--border-width-md)) solid
      var(--image-cropper-selection-border-color, var(--color-primary));
    border-radius: var(--image-cropper-selection-radius, var(--radius-md));
    box-shadow:
      0 0 0 9999px var(--image-cropper-selection-overlay-bg, rgb(0 0 0 / 45%)),
      inset 0 0 0 var(--image-cropper-selection-inner-border-width, var(--border-width-sm))
        var(--image-cropper-selection-inner-border-color, rgb(255 255 255 / 64%));
    outline: 0;
    cursor: grab;
    transition:
      border-color var(--image-cropper-transition, var(--transition-default)),
      box-shadow var(--image-cropper-transition, var(--transition-default));

    &[data-shape='circle'] {
      border-radius: var(--image-cropper-selection-circle-radius, var(--radius-full));
    }

    &:focus-visible {
      box-shadow:
        0 0 0 9999px var(--image-cropper-selection-overlay-bg, rgb(0 0 0 / 45%)),
        inset 0 0 0 var(--image-cropper-selection-inner-border-width, var(--border-width-sm))
          var(--image-cropper-selection-inner-border-color, rgb(255 255 255 / 64%)),
        0 0 0 var(--image-cropper-focus-ring-width, var(--border-width-md))
          var(--image-cropper-focus-ring-color, var(--color-ring));
    }

    &[data-dragging] {
      cursor: grabbing;
    }

    &[data-disabled] {
      cursor: default;
    }
  }

  .grid {
    pointer-events: none;

    &[data-axis='horizontal'] {
      border-block: var(--image-cropper-grid-width, var(--border-width-sm)) solid
        var(--image-cropper-grid-color, rgb(255 255 255 / 62%));
    }

    &[data-axis='vertical'] {
      border-inline: var(--image-cropper-grid-width, var(--border-width-sm)) solid
        var(--image-cropper-grid-color, rgb(255 255 255 / 62%));
    }
  }

  .handle {
    position: absolute;
    z-index: 1;
    box-sizing: border-box;
    width: var(--image-cropper-handle-size, 0.75rem);
    height: var(--image-cropper-handle-size, 0.75rem);
    border: var(--image-cropper-handle-border-width, var(--border-width-sm)) solid
      var(--image-cropper-handle-border-color, rgb(255 255 255 / 88%));
    border-radius: var(--image-cropper-handle-radius, var(--radius-xs));
    background-color: var(--image-cropper-handle-bg, rgb(255 255 255 / 96%));
    box-shadow: var(--image-cropper-handle-shadow, 0 1px 3px rgb(15 23 42 / 18%));
    transition:
      border-color var(--image-cropper-transition, var(--transition-default)),
      background-color var(--image-cropper-transition, var(--transition-default)),
      box-shadow var(--image-cropper-transition, var(--transition-default)),
      opacity var(--image-cropper-transition, var(--transition-default));

    &[data-position='n'],
    &[data-position='s'] {
      width: 100% !important;
      height: var(--image-cropper-handle-edge-thickness, 0.2rem);
      border-width: 0;
      border-radius: var(--image-cropper-handle-edge-radius, var(--radius-full));
    }

    &[data-position='e'],
    &[data-position='w'] {
      width: var(--image-cropper-handle-edge-thickness, 0.2rem);
      height: 100% !important;
      border-width: 0;
      border-radius: var(--image-cropper-handle-edge-radius, var(--radius-full));
    }

    &[data-disabled] {
      display: none;
    }
  }
}
